const generateId = () => Math.random().toString(36).substr(2, 9);

// Helper to create a new user profile in Firestore
export const createFirestoreUser = async (userId: string, email: string, refCode: string | undefined): Promise<User> => {
  const newUser: User = {
    id: userId,
    email,
    referralCode: email.split('@')[0].toUpperCase() + Math.floor(Math.random() * 1000),
    referredBy: refCode || '',
    usdtDepositAddress: 'T' + Math.random().toString(36).substr(2, 33).toUpperCase(),
    capitalBalance: 0,
    profitBalance: 0,
    totalEarned: 0,
    isActive: true,
    isAdmin: false,
    referralCount: 0,
    referralEarnings: 0,
    welcomeBonus: 100 
  };

  await setDoc(doc(db, 'users', userId), newUser);
