                  ))}
               </div>
            </div>
          )}

          {view === 'admin' && (
            <AdminPanel 
              state={{ 
                currentUser, 
                users: [], // Admin view list would need a full fetch
                packages: INITIAL_PACKAGES, 
                activePackages, 
                transactions, 
