                  placeholder="••••••••"
                />
              </div>

              {authMode === 'register' && (
                <div className="space-y-2 group">
                  <p className="text-[10px] font-black uppercase tracking-widest text-white/30">Referral Network ID</p>
                  <input 
                    type="text" 
                    value={refCode}
                    onChange={(e) => setRefCode(e.target.value)}
                    className="w-full bg-transparent border-b border-white/20 py-3 outline-none focus:border-white transition-colors font-mono text-xs uppercase"
                    placeholder="OPTIONAL"
                  />
                </div>
              )}

              <button 
                type="submit"
                disabled={isLoading}
                className="w-full py-5 bg-white text-black text-xs font-black uppercase tracking-[0.3em] hover:bg-white/90 active:scale-[0.98] transition-all flex items-center justify-center gap-4"
              >
                {isLoading ? (
                  <div className="w-4 h-4 border-2 border-black/20 border-t-black rounded-full animate-spin"></div>
                ) : (
                  authMode === 'login' ? 'Enter System' : 'Create Identity'
                )}
              </button>

              <div className="text-center pt-4">
                 <button 
                  type="button"
                  onClick={() => setAuthMode(authMode === 'login' ? 'register' : 'login')}
                  className="text-[10px] font-black uppercase tracking-widest text-white/30 hover:text-white transition-colors"
                 >
                   {authMode === 'login' ? "Register New Identity" : "Return to Login"}
                 </button>
              </div>
            </form>
          </motion.div>
        </div>
      </div>
    );
  }

  return (
    <Layout 
      user={currentUser} 
      onLogout={handleLogout} 
      onNavigate={setView}
      currentView={view}
    >
      <AnimatePresence mode="wait">
        <motion.div
          key={view}
          initial={{ opacity: 0, y: 5 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: -5 }}
          transition={{ duration: 0.3 }}
        >
          {view === 'dashboard' && (
            <Dashboard 
              user={currentUser} 
              transactions={transactions}
              activePackages={activePackages}
            />
          )}

          {view === 'wallet' && (
            <Wallet 
              user={currentUser} 
              onDepositSim={async (a) => {
                await simulateDepositFirestore(currentUser.id, a);
                alert('Deposit simulated and confirmed in Firestore.');
