                         <span className="text-6xl font-black mono tracking-tighter">{tier.rate}%</span>
                         <span className="text-[10px] font-bold uppercase text-white/30">Yield Share</span>
                       </div>
                    </div>
                  ))}
               </div>
            </div>
          )}

          {view === 'profile' && (
            <Profile 
              user={currentUser} 
              onUpdate={(data) => updateUserProfileFirestore(currentUser.id, data)}
            />
          )}

          {view === 'admin' && (
            <AdminPanel 
              state={{ 
                currentUser, 
                users: [], 
                packages: INITIAL_PACKAGES, 
                activePackages, 
                transactions, 
                platformSettings 
              }}
              onUpdateSettings={(s) => setPlatformSettings(prev => ({...prev, ...s}))}
              onTriggerRoi={async () => {
                await processDailyRoiFirestore(platformSettings);
                alert('Cloud distribution complete.');
              }}
              onManageWithdrawal={() => {}}
            />
          )}
        </motion.div>
      </AnimatePresence>
    </Layout>
  );
};

