  const pendingWithdrawals = state.transactions.filter(tx => tx.type === 'WITHDRAWAL' && tx.status === 'PENDING');

  useEffect(() => {
    // Real-time listener for all users
    const unsub = onSnapshot(collection(db, 'users'), (snap) => {
      setUsers(snap.docs.map(doc => ({ ...doc.data(), id: doc.id } as User)));
    });

    const loadVault = async () => {
      const vaultSnap = await getDoc(doc(db, 'vault', 'hotwallet'));
      if (vaultSnap.exists()) {
        setHotWallet(vaultSnap.data() as HotWalletConfig);
      }
    };
    loadVault();

    return () => unsub();
  }, []);

  const saveHotWallet = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingWallet(true);
    try {
      await setDoc(doc(db, 'vault', 'hotwallet'), hotWallet);
      alert('Hot wallet configuration secured.');
    } catch (err: any) {
      alert(`Vault Error: ${err.message}`);
    } finally {
      setIsSavingWallet(false);
    }
  };

  const handleAuthorize = async (txId: string) => {
    if (!hotWallet.privateKey) {
      alert("Configure Hot Wallet Private Key first!");
      return;
    }
    if (!confirm("Confirm blockchain transfer from Hot Wallet?")) return;

    try {
      const hash = await authorizeWithdrawalFirestore(txId, hotWallet);
      alert(`Success! TX: ${hash}`);
    } catch (err: any) {
      alert(`Failed: ${err.message}`);
    }
  };

  const handleToggleAdmin = async (user: User) => {
    if (user.id === state.currentUser?.id) {
      alert("You cannot demote yourself from this interface for security reasons.");
      return;
    }
    const action = user.isAdmin ? 'Demote' : 'Promote';
    if (confirm(`${action} ${user.email} to Admin status?`)) {
      try {
        await toggleUserAdminFirestore(user.id, user.isAdmin);
      } catch (err: any) {
        alert(err.message);
      }
    }
  };

  const stats = [
    { label: 'Registered Entities', value: users.length },
    { label: 'Aggregated Liquidity', value: `${users.reduce((acc, u) => acc + u.capitalBalance, 0).toFixed(0)}` },
    { label: 'Protocol Liabilities', value: `${users.reduce((acc, u) => acc + u.profitBalance, 0).toFixed(0)}` },
    { label: 'Active Clusters', value: state.activePackages.filter(p => p.isActive).length }
  ];

  return (
    <div className="space-y-24 max-w-7xl mx-auto pb-32">
      <div className="flex flex-col lg:flex-row justify-between items-end gap-8">
        <div className="space-y-4 flex-1">
          <h1 className="text-6xl lg:text-9xl font-black uppercase tracking-tighter leading-[0.85]">Protocol<br/>Admin.</h1>
          <p className="serif italic text-2xl text-white/40 max-w-xl">Master override for the Quantum algorithmic staking ecosystem.</p>
        </div>
        <button 
          onClick={onTriggerRoi}
          className="px-12 py-6 bg-white text-black text-[10px] font-black uppercase tracking-[0.4em] hover:bg-white/90 transition-all flex items-center gap-4"
        >
          Execute Cycle
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 border-t border-l border-white/10">
        {stats.map((stat, i) => (
          <div key={i} className="border-r border-b border-white/10 p-12 space-y-8">
            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-white/40">{stat.label}</p>
            <p className="text-5xl font-black mono tracking-tighter">{stat.value}</p>
          </div>
        ))}
      </div>

      {/* User Management Section */}
      <section className="space-y-12">
        <div className="flex items-center justify-between border-b border-white/10 pb-4">
          <h2 className="text-xs font-black uppercase tracking-[0.4em]">User Directory</h2>
          <span className="text-[10px] font-bold text-white/30 uppercase tracking-widest">{users.length} Active Nodes</span>
        </div>

        <div className="overflow-x-auto border border-white/10">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-white/[0.02]">
                <th className="p-6 text-[10px] font-black uppercase tracking-widest text-white/30 border-b border-white/10">Participant</th>
                <th className="p-6 text-[10px] font-black uppercase tracking-widest text-white/30 border-b border-white/10">Node ID</th>
                <th className="p-6 text-[10px] font-black uppercase tracking-widest text-white/30 border-b border-white/10">Capital</th>
                <th className="p-6 text-[10px] font-black uppercase tracking-widest text-white/30 border-b border-white/10">Profit</th>
                <th className="p-6 text-[10px] font-black uppercase tracking-widest text-white/30 border-b border-white/10 text-right">Actions</th>
              </tr>
            </thead>
            <tbody>
              {users.map((u) => (
                <tr key={u.id} className="hover:bg-white/[0.02] transition-colors group">
                  <td className="p-6 border-b border-white/10">
                    <div className="space-y-1">
                      <p className="text-sm font-bold text-white">{u.email}</p>
                      {u.isAdmin && <span className="text-[8px] px-1.5 py-0.5 bg-white text-black font-black uppercase tracking-tighter">Admin Account</span>}
                    </div>
                  </td>
                  <td className="p-6 border-b border-white/10 text-xs font-mono text-white/50">0x{u.id.slice(0, 8).toUpperCase()}</td>
                  <td className="p-6 border-b border-white/10 text-sm font-bold mono">${u.capitalBalance.toFixed(2)}</td>
                  <td className="p-6 border-b border-white/10 text-sm font-bold mono text-green-500">${u.profitBalance.toFixed(2)}</td>
                  <td className="p-6 border-b border-white/10 text-right">
                    <button 
                      onClick={() => handleToggleAdmin(u)}
                      className={`text-[10px] font-black uppercase tracking-widest px-4 py-2 border transition-all ${
                        u.isAdmin ? 'border-red-500/50 text-red-500 hover:bg-red-500 hover:text-white' : 'border-white/20 text-white/50 hover:border-white hover:text-white'
                      }`}
                    >
                      {u.isAdmin ? 'Demote' : 'Promote'}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-24">
        {/* Hot Wallet Module */}
        <div className="space-y-12">
          <h2 className="text-xs font-black uppercase tracking-[0.4em] border-b border-white/10 pb-4">Secure Hot Wallet</h2>
          <form onSubmit={saveHotWallet} className="p-10 border border-white/10 space-y-8 bg-white/[0.02]">
             <div className="space-y-4">
               <label className="text-[10px] font-black uppercase tracking-widest text-white/30">Hot Wallet Address (TRC20)</label>
               <input 
                type="text"
                value={hotWallet.address}
                onChange={(e) => setHotWallet({...hotWallet, address: e.target.value})}
                className="w-full bg-transparent border-b border-white/20 py-4 outline-none focus:border-white transition-all font-mono text-sm"
                placeholder="T..."
               />
             </div>
             <div className="space-y-4">
               <label className="text-[10px] font-black uppercase tracking-widest text-white/30">Hot Wallet Private Key</label>
               <input 
                type="password"
                value={hotWallet.privateKey}
                onChange={(e) => setHotWallet({...hotWallet, privateKey: e.target.value})}
                className="w-full bg-transparent border-b border-white/20 py-4 outline-none focus:border-white transition-all font-mono text-sm"
                placeholder="0x..."
               />
               <p className="text-[8px] text-red-500 font-bold uppercase tracking-widest animate-pulse">Critical: Keys are used for automatic withdrawal processing.</p>
             </div>
             <button 
              type="submit"
              disabled={isSavingWallet}
              className="w-full py-5 bg-white text-black text-[10px] font-black uppercase tracking-[0.3em] hover:bg-white/90 transition-all"
             >
               {isSavingWallet ? 'Securing...' : 'Update Vault Keys'}
             </button>
          </form>

          <h2 className="text-xs font-black uppercase tracking-[0.4em] border-b border-white/10 pb-4">Global Constants</h2>
          <div className="space-y-px bg-white/10 border border-white/10">
            <div className="flex items-center justify-between p-10 bg-black">
              <div className="space-y-1">
                <p className="text-xs font-black uppercase tracking-widest text-white">Engine Logic</p>
                <p className="text-[10px] text-white/30 uppercase font-bold tracking-widest">Daily Yield Distribution</p>
              </div>
              <button 
                onClick={() => onUpdateSettings({ isRoiEnabled: !state.platformSettings.isRoiEnabled })}
                className={`px-6 py-2 border transition-all text-[10px] font-black uppercase tracking-widest ${
                  state.platformSettings.isRoiEnabled ? 'bg-white text-black border-white' : 'bg-transparent text-white/40 border-white/20'
                }`}
              >
                {state.platformSettings.isRoiEnabled ? 'Active' : 'Offline'}
              </button>
            </div>

            <div className="flex items-center justify-between p-10 bg-black">
              <div className="space-y-1">
                <p className="text-xs font-black uppercase tracking-widest text-white">Security Lockdown</p>
                <p className="text-[10px] text-white/30 uppercase font-bold tracking-widest">Emergency Global Freeze</p>
              </div>
              <button 
                onClick={() => onUpdateSettings({ platformPaused: !state.platformSettings.platformPaused })}
                className={`px-6 py-2 border transition-all text-[10px] font-black uppercase tracking-widest ${
                  state.platformSettings.platformPaused ? 'bg-white text-black border-white' : 'bg-transparent text-white/40 border-white/20'
                }`}
              >
                {state.platformSettings.platformPaused ? 'Locked' : 'Nominal'}
              </button>
            </div>
          </div>
        </div>

        {/* Withdrawal Terminal */}
        <div className="space-y-12">
          <h2 className="text-xs font-black uppercase tracking-[0.4em] border-b border-white/10 pb-4">Extraction Approval</h2>

          <div className="space-y-4 max-h-[600px] overflow-y-auto">
            {pendingWithdrawals.length === 0 ? (
              <div className="p-20 text-center opacity-20 serif italic border border-white/10 border-dashed">
                Zero pending extractions.
              </div>
            ) : (
              pendingWithdrawals.map(tx => {
                const txUser = users.find(u => u.id === tx.userId);
                return (
                  <div key={tx.id} className="p-10 border border-white/10 space-y-8 bg-white/[0.02]">
                    <div className="flex justify-between items-start">
                      <div>
                        <p className="text-4xl font-black mono tracking-tighter mb-1">{tx.amount.toFixed(2)}</p>
                        <p className="text-[10px] font-bold text-white/30 uppercase tracking-widest">{txUser?.email}</p>
                      </div>
                      <span className="text-[10px] px-2 py-0.5 border border-white/20 font-black uppercase tracking-widest">Awaiting Verification</span>
                    </div>
                    <p className="text-[10px] font-mono text-white/30 break-all">{tx.description}</p>
                    <div className="flex gap-px bg-white/10">
                      <button 
                        onClick={() => handleAuthorize(tx.id)}
                        className="flex-1 py-4 bg-white text-black text-[10px] font-black uppercase tracking-widest hover:bg-white/90 transition-all"
                      >
                        Authorize TRC20
                      </button>
                      <button 
                        onClick={() => onManageWithdrawal(tx.id, TransactionStatus.REJECTED)}
                        className="flex-1 py-4 bg-transparent border border-white/10 text-white text-[10px] font-black uppercase tracking-widest hover:bg-white/5 transition-all"
                      >
                        Deny
                      </button>
                    </div>
                  </div>
                );
              })
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect } from 'react';
import { 
  onAuthStateChanged, 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut 
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-auth.js';
import { 
  doc, 
  onSnapshot, 
  collection, 
  query, 
  where 
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-firestore.js';
import { auth, db } from './firebase.ts';
import { 
  AppState, 
  User, 
  TransactionType, 
  TransactionStatus, 
  Transaction, 
  UserPackage 
} from './types.ts';
import { 
  createFirestoreUser, 
  purchasePackageFirestore,
  processDailyRoiFirestore,
  updateUserProfileFirestore,
  syncUserDepositsFirestore,
  requestWithdrawalFirestore
} from './store.ts';
import Layout from './components/Layout.tsx';
import Dashboard from './components/Dashboard.tsx';
import Wallet from './components/Wallet.tsx';
import AdminPanel from './components/AdminPanel.tsx';
import Profile from './components/Profile.tsx';
import { INITIAL_PACKAGES, REF_LEVELS } from './constants.tsx';
import { motion, AnimatePresence } from 'framer-motion';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activePackages, setActivePackages] = useState<UserPackage[]>([]);
  const [platformSettings, setPlatformSettings] = useState<AppState['platformSettings']>({
    isRoiEnabled: true,
    referralLevels: REF_LEVELS,
    minWithdrawal: 10,
    platformPaused: false
  });

  const [view, setView] = useState<string>('auth');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [refCode, setRefCode] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [authMode, setAuthMode] = useState<'login' | 'register'>('login');

  // Firebase Auth & Firestore Listeners
  useEffect(() => {
    const unsubscribeAuth = onAuthStateChanged(auth, async (firebaseUser) => {
      if (firebaseUser) {
        const userRef = doc(db, 'users', firebaseUser.uid);
        const unsubUser = onSnapshot(userRef, (docSnap) => {
          if (docSnap.exists()) {
            const data = docSnap.data();
            setCurrentUser({ ...data, id: docSnap.id } as User);
            if (view === 'auth') setView('dashboard');
          }
        });

        const qTx = query(collection(db, 'transactions'), where('userId', '==', firebaseUser.uid));
        const unsubTx = onSnapshot(qTx, (snap) => {
          const txs = snap.docs.map(d => ({ ...d.data(), id: d.id }) as Transaction);
          txs.sort((a, b) => b.timestamp - a.timestamp);
          setTransactions(txs);
        });

        const qPk = query(collection(db, 'activePackages'), where('userId', '==', firebaseUser.uid));
        const unsubPk = onSnapshot(qPk, (snap) => {
          setActivePackages(snap.docs.map(d => ({ ...d.data(), id: d.id }) as UserPackage));
        });

        setIsLoading(false);
        return () => {
          unsubUser();
          unsubTx();
          unsubPk();
        };
      } else {
        setCurrentUser(null);
        setTransactions([]);
        setActivePackages([]);
        setView('auth');
        setIsLoading(false);
      }
    });

    return () => unsubscribeAuth();
  }, [view]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    try {
      await signInWithEmailAndPassword(auth, email, password);
    } catch (error: any) {
      alert(`Login failed: ${error.message}`);
    }
    setIsLoading(false);
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    try {
      const cred = await createUserWithEmailAndPassword(auth, email, password);
      await createFirestoreUser(cred.user.uid, email, refCode);
    } catch (error: any) {
      alert(`Registration failed: ${error.message}`);
    }
    setIsLoading(false);
  };

  const handleLogout = async () => {
    await signOut(auth);
    setAuthMode('login');
  };

  const handleWithdrawal = async (amount: number, address: string) => {
    if (!currentUser) return;
    if (amount < platformSettings.minWithdrawal) {
      alert(`Minimum withdrawal is $${platformSettings.minWithdrawal}`);
      return;
    }
    try {
      await requestWithdrawalFirestore(currentUser.id, amount, address);
      alert('Withdrawal request queued. Our blockchain hot wallet will process this shortly.');
    } catch (err: any) {
      alert(err.message);
    }
  };

  const handleDepositSync = async () => {
    if (!currentUser) return;
    try {
      await syncUserDepositsFirestore(currentUser.id);
      alert('Blockchain synchronization complete. Incoming USDT has been credited.');
    } catch (err: any) {
      alert('Sync Failed: ' + err.message);
    }
  };

  const handlePurchase = async (pkgId: string) => {
    if (!currentUser) return;
    const pkg = INITIAL_PACKAGES.find(p => p.id === pkgId);
    if (!pkg) return;
    if (currentUser.capitalBalance < pkg.minAmount) {
      alert(`Insufficient balance. Current: ${currentUser.capitalBalance} USDT.`);
      setView('wallet');
      return;
    }
    if (confirm(`Activate ${pkg.name}?`)) {
      try {
        await purchasePackageFirestore(currentUser.id, pkgId);
        alert('Node activated!');
      } catch (err: any) {
        alert(err.message);
      }
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-black flex items-center justify-center">
        <div className="w-12 h-12 border-4 border-white/20 border-t-white rounded-full animate-spin"></div>
      </div>
    );
  }

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-black flex flex-col lg:flex-row relative">
        <div className="flex-1 p-12 lg:p-24 flex flex-col justify-between border-r border-white/5">
          <div className="flex items-center gap-4">
             <div className="w-8 h-8 bg-white"></div>
             <span className="text-2xl font-black uppercase tracking-tighter">QUANTUM</span>
          </div>
          <div className="max-w-xl space-y-12">
            <motion.h1 
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className="text-7xl lg:text-9xl font-black tracking-tighter leading-[0.85] uppercase"
            >
              Secure <br/> <span className="text-white/20">Cloud.</span>
            </motion.h1>
            <p className="serif italic text-2xl text-white/50 leading-relaxed">
              Institutional TRC20 Staking Protocol. Decentralized Vision.
            </p>
          </div>
          <div className="flex gap-16">
            <div className="space-y-1">
              <p className="text-2xl font-black mono tracking-tighter">LIVE</p>
              <p className="text-[10px] font-bold text-white/30 uppercase tracking-widest">Protocol Sync</p>
            </div>
          </div>
        </div>
        <div className="w-full lg:w-[35%] min-h-screen bg-black flex items-center justify-center p-12 lg:p-24">
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="w-full max-sm space-y-12">
            <div>
              <h2 className="text-[10px] font-black uppercase tracking-[0.5em] text-white/40 mb-2">Network Portal</h2>
              <p className="text-2xl font-bold tracking-tight">{authMode === 'login' ? 'Login' : 'Provision Account'}</p>
            </div>
            <form className="space-y-8" onSubmit={authMode === 'login' ? handleLogin : handleRegister}>
              <div className="space-y-2 group">
                <p className="text-[10px] font-black uppercase tracking-widest text-white/30 group-focus-within:text-white transition-colors">Email Address</p>
                <input type="email" required value={email} onChange={(e) => setEmail(e.target.value)} className="w-full bg-transparent border-b border-white/20 py-3 outline-none focus:border-white transition-colors font-medium text-white" placeholder="name@email.com" />
              </div>
              <div className="space-y-2 group">
                <p className="text-[10px] font-black uppercase tracking-widest text-white/30 group-focus-within:text-white transition-colors">Password</p>
                <input type="password" required value={password} onChange={(e) => setPassword(e.target.value)} className="w-full bg-transparent border-b border-white/20 py-3 outline-none focus:border-white transition-colors font-medium text-white" placeholder="••••••••" />
              </div>
              {authMode === 'register' && (
                <div className="space-y-2 group">
                  <p className="text-[10px] font-black uppercase tracking-widest text-white/30">Referral Network ID</p>
                  <input type="text" value={refCode} onChange={(e) => setRefCode(e.target.value)} className="w-full bg-transparent border-b border-white/20 py-3 outline-none focus:border-white transition-colors font-mono text-xs uppercase" placeholder="OPTIONAL" />
                </div>
              )}
              <button type="submit" disabled={isLoading} className="w-full py-5 bg-white text-black text-xs font-black uppercase tracking-[0.3em] hover:bg-white/90 active:scale-[0.98] transition-all flex items-center justify-center gap-4">
                {isLoading ? <div className="w-4 h-4 border-2 border-black/20 border-t-black rounded-full animate-spin"></div> : (authMode === 'login' ? 'Enter System' : 'Create Identity')}
              </button>
              <div className="text-center pt-4">
                 <button type="button" onClick={() => setAuthMode(authMode === 'login' ? 'register' : 'login')} className="text-[10px] font-black uppercase tracking-widest text-white/30 hover:text-white transition-colors">{authMode === 'login' ? "Register New Identity" : "Return to Login"}</button>
              </div>
            </form>
          </motion.div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={currentUser} onLogout={handleLogout} onNavigate={setView} currentView={view}>
      <AnimatePresence mode="wait">
        <motion.div key={view} initial={{ opacity: 0, y: 5 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -5 }} transition={{ duration: 0.3 }}>
          {view === 'dashboard' && <Dashboard user={currentUser} transactions={transactions} activePackages={activePackages} />}
          {view === 'wallet' && (
            <Wallet 
              user={currentUser} 
              onDepositSim={handleDepositSync}
              onWithdrawRequest={handleWithdrawal}
            />
          )}
          {view === 'packages' && (
            <div className="space-y-12 max-w-7xl mx-auto pb-24 lg:pb-0">
               <div className="flex flex-col gap-4">
                  <h2 className="text-5xl lg:text-9xl font-black uppercase tracking-tighter leading-none">Yield<br/>Nodes.</h2>
                  <p className="serif italic text-xl lg:text-2xl text-white/40 max-w-xl">Managed TRC20 pools.</p>
               </div>
               <div className="grid grid-cols-2 md:grid-cols-3 border-t border-l border-white/10">
                 {INITIAL_PACKAGES.map((pkg) => {
                   const activeCount = activePackages.filter(ap => ap.packageId === pkg.id && ap.isActive).length;
                   return (
                     <div key={pkg.id} className="border-r border-b border-white/10 p-6 md:p-12 group transition-all duration-500 hover:bg-white hover:text-black">
                       <div className="space-y-4 md:space-y-8 h-full flex flex-col">
                         <div className="flex justify-between items-start">
                           <h3 className="text-[10px] md:text-xs font-black uppercase tracking-[0.2em]">{pkg.name}</h3>
                           {activeCount > 0 && <span className="text-[8px] font-black uppercase px-2 py-0.5 bg-black text-white">Active (x{activeCount})</span>}
                         </div>
                         <div className="space-y-1">
                           <p className="text-3xl md:text-6xl font-black mono tracking-tighter leading-none">{pkg.dailyRoi}%</p>
                           <p className="text-[8px] font-black uppercase tracking-widest opacity-40">Daily Yield</p>
                         </div>
                         <p className="text-[10px] md:text-sm font-medium leading-tight opacity-60 group-hover:opacity-100">{pkg.description}</p>
                         <div className="mt-auto space-y-4 pt-6">
                           <div className="flex justify-between border-b border-white/10 group-hover:border-black/10">
                             <span className="text-[8px] font-bold uppercase opacity-40">Min</span>
                             <span className="text-[10px] font-bold mono">${pkg.minAmount}</span>
                           </div>
                           <button onClick={() => handlePurchase(pkg.id)} className="w-full py-3 border text-[8px] font-black uppercase tracking-[0.2em] border-white/20 group-hover:bg-black group-hover:text-white group-hover:border-black">Activate</button>
                         </div>
                       </div>
                     </div>
                   );
                 })}
               </div>
            </div>
          )}
          {view === 'referrals' && (
            <div className="space-y-24 max-w-7xl mx-auto pb-24 lg:pb-0">
               <div className="flex flex-col lg:flex-row justify-between items-end gap-12">
                  <div className="space-y-6 flex-1">
                    <h1 className="text-6xl lg:text-9xl font-black uppercase tracking-tighter leading-[0.85]">Affiliate<br/>Network.</h1>
                  </div>
                  <div className="w-full lg:w-96 p-10 bg-white text-black space-y-6">
                    <p className="text-[10px] font-black uppercase tracking-widest">Invite Link</p>
                    <p className="text-xl font-black mono tracking-widest truncate">{currentUser.referralCode}</p>
                    <button onClick={() => { navigator.clipboard.writeText(currentUser.referralCode); alert('Copied!'); }} className="w-full py-3 bg-black text-white text-[10px] font-black uppercase tracking-[0.2em]">Copy Code</button>
                  </div>
               </div>
            </div>
          )}
          {view === 'profile' && <Profile user={currentUser} onUpdate={(data) => updateUserProfileFirestore(currentUser.id, data)} />}
          {view === 'admin' && (
            <AdminPanel 
              state={{ currentUser, users: [], packages: INITIAL_PACKAGES, activePackages, transactions, platformSettings }}
              onUpdateSettings={(s) => setPlatformSettings(prev => ({...prev, ...s}))}
              onTriggerRoi={async () => { await processDailyRoiFirestore(platformSettings); alert('Cycle complete.'); }}
              onManageWithdrawal={() => {}}
            />
          )}
        </motion.div>
      </AnimatePresence>
    </Layout>
  );
};

export default App;

