  );
};

export default Layout;

import React, { useState, useEffect } from 'react';
import { 
  onAuthStateChanged, 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut 
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-auth.js';
import { 
  doc, 
  onSnapshot, 
  collection, 
  query, 
  where 
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-firestore.js';
import { auth, db } from './firebase.ts';
import { 
  AppState, 
  User, 
  TransactionType, 
  TransactionStatus, 
  Transaction, 
  UserPackage 
} from './types.ts';
import { 
  createFirestoreUser, 
  purchasePackageFirestore,
  processDailyRoiFirestore,
  updateUserProfileFirestore,
  syncUserDepositsFirestore,
  requestWithdrawalFirestore
} from './store.ts';
import Layout from './components/Layout.tsx';
import Dashboard from './components/Dashboard.tsx';
import Wallet from './components/Wallet.tsx';
import AdminPanel from './components/AdminPanel.tsx';
import Profile from './components/Profile.tsx';
import { INITIAL_PACKAGES, REF_LEVELS } from './constants.tsx';
import { motion, AnimatePresence } from 'framer-motion';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activePackages, setActivePackages] = useState<UserPackage[]>([]);
  const [platformSettings, setPlatformSettings] = useState<AppState['platformSettings']>({
    isRoiEnabled: true,
    referralLevels: REF_LEVELS,
    minWithdrawal: 10,
    platformPaused: false
  });

  const [view, setView] = useState<string>('auth');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [refCode, setRefCode] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [authMode, setAuthMode] = useState<'login' | 'register'>('login');

  // Firebase Auth & Firestore Listeners
  useEffect(() => {
    const unsubscribeAuth = onAuthStateChanged(auth, async (firebaseUser) => {
      if (firebaseUser) {
        const userRef = doc(db, 'users', firebaseUser.uid);
        const unsubUser = onSnapshot(userRef, (docSnap) => {
          if (docSnap.exists()) {
            const data = docSnap.data();
            setCurrentUser({ ...data, id: docSnap.id } as User);
            if (view === 'auth') setView('dashboard');
          }
        }, (err) => {
          console.warn("User profile sync blocked:", err.message);
        });

        const qTx = query(collection(db, 'transactions'), where('userId', '==', firebaseUser.uid));
        const unsubTx = onSnapshot(qTx, (snap) => {
          const txs = snap.docs.map(d => ({ ...d.data(), id: d.id }) as Transaction);
          txs.sort((a, b) => b.timestamp - a.timestamp);
          setTransactions(txs);
        }, (err) => {
          console.warn("Transaction sync blocked:", err.message);
        });

        const qPk = query(collection(db, 'activePackages'), where('userId', '==', firebaseUser.uid));
        const unsubPk = onSnapshot(qPk, (snap) => {
          setActivePackages(snap.docs.map(d => ({ ...d.data(), id: d.id }) as UserPackage));
        }, (err) => {
          console.warn("Packages sync blocked:", err.message);
        });

        setIsLoading(false);
        return () => {
          unsubUser();
          unsubTx();
          unsubPk();
        };
      } else {
        setCurrentUser(null);
        setTransactions([]);
        setActivePackages([]);
        setView('auth');
        setIsLoading(false);
      }
    });

    return () => unsubscribeAuth();
  }, [view]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    try {
      await signInWithEmailAndPassword(auth, email, password);
    } catch (error: any) {
      alert(`Login failed: ${error.message}`);
    }
    setIsLoading(false);
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    try {
      const cred = await createUserWithEmailAndPassword(auth, email, password);
      await createFirestoreUser(cred.user.uid, email, refCode);
    } catch (error: any) {
      alert(`Registration failed: ${error.message}`);
    }
    setIsLoading(false);
  };

  const handleLogout = async () => {
    try {
      await signOut(auth);
      setAuthMode('login');
      setView('auth');
    } catch (err: any) {
      console.error("Logout error:", err);
    }
  };

  const handleWithdrawal = async (amount: number, address: string) => {
    if (!currentUser) return;
    if (amount < platformSettings.minWithdrawal) {
      alert(`Minimum withdrawal is $${platformSettings.minWithdrawal}`);
      return;
    }
    try {
      await requestWithdrawalFirestore(currentUser.id, amount, address);
      alert('Withdrawal request queued. Our blockchain hot wallet will process this shortly.');
    } catch (err: any) {
      alert(err.message);
    }
  };

  const handleDepositSync = async () => {
    if (!currentUser) return;
    try {
      await syncUserDepositsFirestore(currentUser.id);
      alert('Blockchain synchronization complete. Incoming USDT has been credited.');
    } catch (err: any) {
      alert('Sync Failed: ' + err.message);
    }
  };

  const handlePurchase = async (pkgId: string) => {
    if (!currentUser) return;
    const pkg = INITIAL_PACKAGES.find(p => p.id === pkgId);
    if (!pkg) return;
    if (currentUser.capitalBalance < pkg.minAmount) {
      alert(`Insufficient balance. Current: ${currentUser.capitalBalance} USDT.`);
      setView('wallet');
      return;
    }
    if (confirm(`Activate ${pkg.name}?`)) {
      try {
        await purchasePackageFirestore(currentUser.id, pkgId);
        alert('Node activated!');
      } catch (err: any) {
        alert(err.message);
      }
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-black flex items-center justify-center">
        <div className="w-12 h-12 border-4 border-white/20 border-t-white rounded-full animate-spin"></div>
      </div>
    );
  }

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-black flex flex-col lg:flex-row relative">
        <div className="flex-1 p-12 lg:p-24 flex flex-col justify-between border-r border-white/5">
          <div className="flex items-center gap-4">
             <div className="w-8 h-8 bg-white"></div>
             <span className="text-2xl font-black uppercase tracking-tighter">QUANTUM</span>
          </div>
          <div className="max-w-xl space-y-12">
            <motion.h1 
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className="text-7xl lg:text-9xl font-black tracking-tighter leading-[0.85] uppercase"
            >
              Secure <br/> <span className="text-white/20">Cloud.</span>
            </motion.h1>
            <p className="serif italic text-2xl text-white/50 leading-relaxed">
              Institutional TRC20 Staking Protocol. Decentralized Vision.
            </p>
          </div>
          <div className="flex gap-16">
            <div className="space-y-1">
              <p className="text-2xl font-black mono tracking-tighter">LIVE</p>
              <p className="text-[10px] font-bold text-white/30 uppercase tracking-widest">Protocol Sync</p>
            </div>
          </div>
        </div>
        <div className="w-full lg:w-[35%] min-h-screen bg-black flex items-center justify-center p-12 lg:p-24">
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="w-full max-sm space-y-12">
            <div>
              <h2 className="text-[10px] font-black uppercase tracking-[0.5em] text-white/40 mb-2">Network Portal</h2>
              <p className="text-2xl font-bold tracking-tight">{authMode === 'login' ? 'Login' : 'Provision Account'}</p>
            </div>
            <form className="space-y-8" onSubmit={authMode === 'login' ? handleLogin : handleRegister}>
              <div className="space-y-2 group">
                <p className="text-[10px] font-black uppercase tracking-widest text-white/30 group-focus-within:text-white transition-colors">Email Address</p>
                <input type="email" required value={email} onChange={(e) => setEmail(e.target.value)} className="w-full bg-transparent border-b border-white/20 py-3 outline-none focus:border-white transition-colors font-medium text-white" placeholder="name@email.com" />
              </div>
              <div className="space-y-2 group">
                <p className="text-[10px] font-black uppercase tracking-widest text-white/30 group-focus-within:text-white transition-colors">Password</p>
                <input type="password" required value={password} onChange={(e) => setPassword(e.target.value)} className="w-full bg-transparent border-b border-white/20 py-3 outline-none focus:border-white transition-colors font-medium text-white" placeholder="••••••••" />
              </div>
              {authMode === 'register' && (
                <div className="space-y-2 group">
                  <p className="text-[10px] font-black uppercase tracking-widest text-white/30">Referral Network ID</p>
                  <input type="text" value={refCode} onChange={(e) => setRefCode(e.target.value)} className="w-full bg-transparent border-b border-white/20 py-3 outline-none focus:border-white transition-colors font-mono text-xs uppercase" placeholder="OPTIONAL" />
                </div>
              )}
              <button type="submit" disabled={isLoading} className="w-full py-5 bg-white text-black text-xs font-black uppercase tracking-[0.3em] hover:bg-white/90 active:scale-[0.98] transition-all flex items-center justify-center gap-4">
                {isLoading ? <div className="w-4 h-4 border-2 border-black/20 border-t-black rounded-full animate-spin"></div> : (authMode === 'login' ? 'Enter System' : 'Create Identity')}
              </button>
              <div className="text-center pt-4">
                 <button type="button" onClick={() => setAuthMode(authMode === 'login' ? 'register' : 'login')} className="text-[10px] font-black uppercase tracking-widest text-white/30 hover:text-white transition-colors">{authMode === 'login' ? "Register New Identity" : "Return to Login"}</button>
              </div>
            </form>
          </motion.div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={currentUser} onLogout={handleLogout} onNavigate={setView} currentView={view}>
      <AnimatePresence mode="wait">
        <motion.div key={view} initial={{ opacity: 0, y: 5 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -5 }} transition={{ duration: 0.3 }}>
          {view === 'dashboard' && <Dashboard user={currentUser} transactions={transactions} activePackages={activePackages} />}
          {view === 'wallet' && (
            <Wallet 
              user={currentUser} 
              onDepositSim={handleDepositSync}
              onWithdrawRequest={handleWithdrawal}
            />
          )}
          {view === 'packages' && (
            <div className="space-y-12 max-w-7xl mx-auto pb-24 lg:pb-0">
               <div className="flex flex-col gap-4">
                  <h2 className="text-5xl lg:text-9xl font-black uppercase tracking-tighter leading-none">Yield<br/>Nodes.</h2>
                  <p className="serif italic text-xl lg:text-2xl text-white/40 max-w-xl">Managed TRC20 pools.</p>
               </div>
               <div className="grid grid-cols-2 md:grid-cols-3 border-t border-l border-white/10">
                 {INITIAL_PACKAGES.map((pkg) => {
                   const activeCount = activePackages.filter(ap => ap.packageId === pkg.id && ap.isActive).length;
                   return (
                     <div key={pkg.id} className="border-r border-b border-white/10 p-6 md:p-12 group transition-all duration-500 hover:bg-white hover:text-black">
                       <div className="space-y-4 md:space-y-8 h-full flex flex-col">
                         <div className="flex justify-between items-start">
                           <h3 className="text-[10px] md:text-xs font-black uppercase tracking-[0.2em]">{pkg.name}</h3>
                           {activeCount > 0 && <span className="text-[8px] font-black uppercase px-2 py-0.5 bg-black text-white">Active (x{activeCount})</span>}
                         </div>
                         <div className="space-y-1">
                           <p className="text-3xl md:text-6xl font-black mono tracking-tighter leading-none">{pkg.dailyRoi}%</p>
                           <p className="text-[8px] font-black uppercase tracking-widest opacity-40">Daily Yield</p>
                         </div>
                         <p className="text-[10px] md:text-sm font-medium leading-tight opacity-60 group-hover:opacity-100">{pkg.description}</p>
                         <div className="mt-auto space-y-4 pt-6">
                           <div className="flex justify-between border-b border-white/10 group-hover:border-black/10">
                             <span className="text-[8px] font-bold uppercase opacity-40">Min</span>
                             <span className="text-[10px] font-bold mono">${pkg.minAmount}</span>
                           </div>
                           <button onClick={() => handlePurchase(pkg.id)} className="w-full py-3 border text-[8px] font-black uppercase tracking-[0.2em] border-white/20 group-hover:bg-black group-hover:text-white group-hover:border-black">Activate</button>
                         </div>
                       </div>
                     </div>
                   );
                 })}
               </div>
            </div>
          )}
          {view === 'referrals' && (
            <div className="space-y-24 max-w-7xl mx-auto pb-24 lg:pb-0">
               <div className="flex flex-col lg:flex-row justify-between items-end gap-12">
                  <div className="space-y-6 flex-1">
