                  </div>
               </div>
            </div>
          )}
          {view === 'profile' && <Profile user={currentUser} onUpdate={(data) => updateUserProfileFirestore(currentUser.id, data)} />}
          {view === 'admin' && (
            <AdminPanel 
              state={{ currentUser, users: [], packages: INITIAL_PACKAGES, activePackages, transactions, platformSettings }}
              onUpdateSettings={(s) => setPlatformSettings(prev => ({...prev, ...s}))}
              onTriggerRoi={async () => { await processDailyRoiFirestore(platformSettings); alert('Cycle complete.'); }}
              onManageWithdrawal={() => {}}
            />
          )}
        </motion.div>
      </AnimatePresence>
    </Layout>
  );
};

