import React, { useState, useEffect } from 'react';
import { AppState, User, TransactionStatus, HotWalletConfig } from '../types.ts';
import { doc, getDoc, setDoc, collection, onSnapshot } from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-firestore.js';
import { db } from '../firebase.ts';
import { authorizeWithdrawalFirestore, toggleUserAdminFirestore } from '../store.ts';

interface AdminPanelProps {
  state: AppState;
  onUpdateSettings: (settings: Partial<AppState['platformSettings']>) => void;
  onTriggerRoi: (e?: React.MouseEvent) => void;
  onManageWithdrawal: (txId: string, status: TransactionStatus) => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ state, onUpdateSettings, onTriggerRoi, onManageWithdrawal }) => {
  const [users, setUsers] = useState<User[]>([]);
  const [hotWallet, setHotWallet] = useState<HotWalletConfig>({
    address: '',
    privateKey: '',
    lastSyncTimestamp: Date.now()
  });
  const [isSavingWallet, setIsSavingWallet] = useState(false);

  const pendingWithdrawals = state.transactions.filter(tx => tx.type === 'WITHDRAWAL' && tx.status === 'PENDING');

  useEffect(() => {
    // Real-time listener for all users
    const unsub = onSnapshot(collection(db, 'users'), (snap) => {
      setUsers(snap.docs.map(d => ({ ...d.data(), id: d.id } as User)));
    });

    const loadVault = async () => {
      const vaultSnap = await getDoc(doc(db, 'vault', 'hotwallet'));
      if (vaultSnap.exists()) {
        setHotWallet(vaultSnap.data() as HotWalletConfig);
      }
    };
    loadVault();

    return () => unsub();
  }, []);

  const saveHotWallet = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingWallet(true);
    try {
      await setDoc(doc(db, 'vault', 'hotwallet'), hotWallet);
      alert('Hot wallet configuration secured.');
    } catch (err: any) {
      alert(`Vault Error: ${err.message}`);
    } finally {
      setIsSavingWallet(false);
    }
  };

  const handleAuthorize = async (txId: string) => {
    if (!hotWallet.privateKey) {
      alert("Configure Hot Wallet Private Key first!");
      return;
    }
    if (!confirm("Confirm blockchain transfer from Hot Wallet?")) return;

    try {
      const hash = await authorizeWithdrawalFirestore(txId, hotWallet);
      alert(`Success! TX: ${hash}`);
    } catch (err: any) {
      alert(`Failed: ${err.message}`);
    }
  };

  const handleToggleAdmin = async (user: User) => {
    if (user.id === state.currentUser?.id) {
      alert("You cannot demote yourself from this interface for security reasons.");
      return;
    }
    const action = user.isAdmin ? 'Demote' : 'Promote';
    if (confirm(`${action} ${user.email} to Admin status?`)) {
      try {
        await toggleUserAdminFirestore(user.id, user.isAdmin);
      } catch (err: any) {
        alert(err.message);
      }
    }
  };

  const stats = [
    { label: 'Registered Entities', value: users.length },
    { label: 'Aggregated Liquidity', value: `${users.reduce((acc, u) => acc + u.capitalBalance, 0).toFixed(0)}` },
    { label: 'Protocol Liabilities', value: `${users.reduce((acc, u) => acc + u.profitBalance, 0).toFixed(0)}` },
    { label: 'Active Clusters', value: state.activePackages.filter(p => p.isActive).length }
  ];

  return (
    <div className="space-y-24 max-w-7xl mx-auto pb-32">
      <div className="flex flex-col lg:flex-row justify-between items-end gap-8">
        <div className="space-y-4 flex-1">
          <h1 className="text-6xl lg:text-9xl font-black uppercase tracking-tighter leading-[0.85]">Protocol<br/>Admin.</h1>
          <p className="serif italic text-2xl text-white/40 max-w-xl">Master override for the Quantum algorithmic staking ecosystem.</p>
        </div>
        <button 
          onClick={() => onTriggerRoi()}
          className="px-12 py-6 bg-white text-black text-[10px] font-black uppercase tracking-[0.4em] hover:bg-white/90 transition-all flex items-center gap-4"
        >
          Execute Cycle
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 border-t border-l border-white/10">
        {stats.map((stat, i) => (
          <div key={i} className="border-r border-b border-white/10 p-12 space-y-8">
            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-white/40">{stat.label}</p>
            <p className="text-5xl font-black mono tracking-tighter">{stat.value}</p>
          </div>
        ))}
      </div>

      {/* User Management Section */}
      <section className="space-y-12">
        <div className="flex items-center justify-between border-b border-white/10 pb-4">
          <h2 className="text-xs font-black uppercase tracking-[0.4em]">User Directory</h2>
          <span className="text-[10px] font-bold text-white/30 uppercase tracking-widest">{users.length} Active Nodes</span>
        </div>

        <div className="overflow-x-auto border border-white/10">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-white/[0.02]">
                <th className="p-6 text-[10px] font-black uppercase tracking-widest text-white/30 border-b border-white/10">Participant</th>
                <th className="p-6 text-[10px] font-black uppercase tracking-widest text-white/30 border-b border-white/10">Node ID</th>
                <th className="p-6 text-[10px] font-black uppercase tracking-widest text-white/30 border-b border-white/10">Capital</th>
                <th className="p-6 text-[10px] font-black uppercase tracking-widest text-white/30 border-b border-white/10">Profit</th>
                <th className="p-6 text-[10px] font-black uppercase tracking-widest text-white/30 border-b border-white/10 text-right">Actions</th>
              </tr>
            </thead>
            <tbody>
              {users.map((u) => (
                <tr key={u.id} className="hover:bg-white/[0.02] transition-colors group">
                  <td className="p-6 border-b border-white/10">
                    <div className="space-y-1">
                      <p className="text-sm font-bold text-white">{u.email}</p>
                      {u.isAdmin && <span className="text-[8px] px-1.5 py-0.5 bg-white text-black font-black uppercase tracking-tighter">Admin Account</span>}
                    </div>
                  </td>
                  <td className="p-6 border-b border-white/10 text-xs font-mono text-white/50">0x{u.id.slice(0, 8).toUpperCase()}</td>
                  <td className="p-6 border-b border-white/10 text-sm font-bold mono">${u.capitalBalance.toFixed(2)}</td>
                  <td className="p-6 border-b border-white/10 text-sm font-bold mono text-green-500">${u.profitBalance.toFixed(2)}</td>
                  <td className="p-6 border-b border-white/10 text-right">
                    <button 
                      onClick={() => handleToggleAdmin(u)}
                      className={`text-[10px] font-black uppercase tracking-widest px-4 py-2 border transition-all ${
                        u.isAdmin ? 'border-red-500/50 text-red-500 hover:bg-red-500 hover:text-white' : 'border-white/20 text-white/50 hover:border-white hover:text-white'
                      }`}
                    >
