                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-24">
        {/* Hot Wallet Module */}
        <div className="space-y-12">
          <h2 className="text-xs font-black uppercase tracking-[0.4em] border-b border-white/10 pb-4">Secure Hot Wallet</h2>
          <form onSubmit={saveHotWallet} className="p-10 border border-white/10 space-y-8 bg-white/[0.02]">
             <div className="space-y-4">
               <label className="text-[10px] font-black uppercase tracking-widest text-white/30">Hot Wallet Address (TRC20)</label>
               <input 
                type="text"
                value={hotWallet.address}
                onChange={(e) => setHotWallet({...hotWallet, address: e.target.value})}
                className="w-full bg-transparent border-b border-white/20 py-4 outline-none focus:border-white transition-all font-mono text-sm"
                placeholder="T..."
               />
             </div>
             <div className="space-y-4">
               <label className="text-[10px] font-black uppercase tracking-widest text-white/30">Hot Wallet Private Key</label>
               <input 
                type="password"
                value={hotWallet.privateKey}
                onChange={(e) => setHotWallet({...hotWallet, privateKey: e.target.value})}
                className="w-full bg-transparent border-b border-white/20 py-4 outline-none focus:border-white transition-all font-mono text-sm"
                placeholder="0x..."
               />
               <p className="text-[8px] text-red-500 font-bold uppercase tracking-widest animate-pulse">Critical: Keys are used for automatic withdrawal processing.</p>
             </div>
             <button 
              type="submit"
              disabled={isSavingWallet}
              className="w-full py-5 bg-white text-black text-[10px] font-black uppercase tracking-[0.3em] hover:bg-white/90 transition-all"
             >
               {isSavingWallet ? 'Securing...' : 'Update Vault Keys'}
             </button>
          </form>

          <h2 className="text-xs font-black uppercase tracking-[0.4em] border-b border-white/10 pb-4">Global Constants</h2>
          <div className="space-y-px bg-white/10 border border-white/10">
            <div className="flex items-center justify-between p-10 bg-black">
              <div className="space-y-1">
                <p className="text-xs font-black uppercase tracking-widest text-white">Engine Logic</p>
                <p className="text-[10px] text-white/30 uppercase font-bold tracking-widest">Daily Yield Distribution</p>
              </div>
              <button 
                onClick={() => onUpdateSettings({ isRoiEnabled: !state.platformSettings.isRoiEnabled })}
