                return (
                  <div key={tx.id} className="p-10 border border-white/10 space-y-8 bg-white/[0.02]">
                    <div className="flex justify-between items-start">
                      <div>
                        <p className="text-4xl font-black mono tracking-tighter mb-1">{tx.amount.toFixed(2)}</p>
                        <p className="text-[10px] font-bold text-white/30 uppercase tracking-widest">{txUser?.email}</p>
