            const userData = { ...docSnap.data(), id: docSnap.id } as User;
            setCurrentUser(userData);
            setIsProvisioning(false);

            // Success: Switch to dashboard if we are still on auth screen
            setView(prev => prev === 'auth' ? 'dashboard' : prev);
            setIsLoading(false);
          } else {
            // Profile doc doesn't exist yet (usually during registration)
            // We stay in a "provisioning" loading state
            console.log("Profile not found for authenticated user, waiting for creation...");
            setIsProvisioning(true);

            // Safety timeout: If after 10 seconds we still don't have a doc, stop loading
            // and maybe something went wrong during creation.
            const timeout = setTimeout(() => {
              if (auth.currentUser && !currentUser) {
                console.warn("Profile creation timeout.");
                setIsLoading(false);
                setIsProvisioning(false);
              }
            }, 10000);
            return () => clearTimeout(timeout);
          }
        }, (err) => {
          console.error("Profile Sync Error:", err);
          setIsLoading(false);
        });

        // Sync Transactions & Packages
        unsubTx = onSnapshot(query(collection(db, 'transactions'), where('userId', '==', firebaseUser.uid)), (snap) => {
          setTransactions(snap.docs.map(d => ({ ...d.data(), id: d.id }) as Transaction).sort((a, b) => b.timestamp - a.timestamp));
        });

        unsubPk = onSnapshot(query(collection(db, 'activePackages'), where('userId', '==', firebaseUser.uid)), (snap) => {
          setActivePackages(snap.docs.map(d => ({ ...d.data(), id: d.id }) as UserPackage));
        });

      } else {
        // No user logged in
        setCurrentUser(null);
        setTransactions([]);
        setActivePackages([]);
        setView('auth');
        setIsLoading(false);
        setIsProvisioning(false);
      }
    });

    return () => {
      unsubscribeAuth();
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();
    };
